targets.expr:
sum(
  rate(
    traefik_router_requests_total{
      host=~"$host",
      router=~"$router",
      pod=~"$pod"
    }[1m]
  )
)

round(
  sum by (le)(
    increase(
      traefik_router_request_duration_seconds_bucket{
        code!="404",code!~"[5].*",
        router =~ "$router",
      }[2m]
    )
  )
)

sum(
  rate(
    traefik_router_requests_total{
      host=~"$host",
      router=~"$router",
      pod=~"$pod"
    }[1m]
  )
) by (router)
